import os, sys, json, argparse, math
import numpy as np
from collections import deque
import cogniplan_env
from cogniplan_env import ExplorationEnv


def euclidean(p1, p2):
    """Euclidean distance between two points."""
    return math.hypot(p1[0] - p2[0], p1[1] - p2[1])


def build_graph(nodes):
    """Build adjacency list from nodes list."""
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord = (n['coords'][0], n['coords'][1])
        coord_to_idx[coord] = i
    adj = [[] for _ in nodes]
    for i, n in enumerate(nodes):
        for nb_coord in n.get('neighbors', []):
            nb_key = (nb_coord[0], nb_coord[1])
            if nb_key in coord_to_idx:
                adj[i].append(coord_to_idx[nb_key])
    return coord_to_idx, adj


def bfs_shortest_path(start_coord, target_coord, coord_to_idx, adj, nodes):
    """Return list of node coords from start_coord to target_coord (excluding start)."""
    start_idx = coord_to_idx.get(start_coord)
    target_idx = coord_to_idx.get(target_coord)
    if start_idx is None or target_idx is None:
        return None
    if start_idx == target_idx:
        return []
    parent = [-1] * len(nodes)
    visited = [False] * len(nodes)
    q = deque([start_idx])
    visited[start_idx] = True
    while q:
        u = q.popleft()
        for v in adj[u]:
            if not visited[v]:
                visited[v] = True
                parent[v] = u
                if v == target_idx:
                    path = []
                    while v != start_idx:
                        path.append(v)
                        v = parent[v]
                    path.reverse()
                    return [nodes[i]['coords'] for i in path]
                q.append(v)
    return None


def closest_node_to(pos, nodes):
    """Find closest node coordinate to given position."""
    min_d = float('inf')
    best = None
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        d = euclidean(pos, coord)
        if d < min_d:
            min_d = d
            best = coord
    return best


def smart_policy(obs, current_node_coord, coord_to_idx, adj, nodes, visited_nodes):
    """
    Advanced exploration policy:
    1. Immediate high-utility neighbour.
    2. Global best utility node via BFS.
    3. Closest frontier via nearest node.
    """
    neighbors = obs.get('neighbors', [])
    if not neighbors:
        return None
    neighbor_set = set(tuple(nb) for nb in neighbors)

    # 1. Immediate neighbour with utility > 0
    best_util_neighbor = None
    best_util = -1
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        if coord in neighbor_set:
            util = n.get('utility', 0)
            if coord in visited_nodes:
                util *= 0.5  # discourage loops
            if util > best_util:
                best_util = util
                best_util_neighbor = coord
    if best_util > 0:
        return best_util_neighbor

    # 2. Global best utility node (unvisited)
    target_coord = None
    max_util = -1
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        util = n.get('utility', 0)
        if coord in visited_nodes:
            util *= 0.5
        if util > max_util:
            max_util = util
            target_coord = coord
    if target_coord is not None and max_util > 0:
        path = bfs_shortest_path(current_node_coord, target_coord, coord_to_idx, adj, nodes)
        if path and len(path) > 0:
            next_node = path[0]
            if next_node in neighbor_set:
                return next_node

    # 3. Closest frontier
    frontiers = obs.get('frontiers', [])
    if frontiers:
        closest_frontier = min(frontiers, key=lambda f: euclidean(current_node_coord, f))
        nearest_node_coord = closest_node_to(closest_frontier, nodes)
        if nearest_node_coord:
            path = bfs_shortest_path(current_node_coord, nearest_node_coord, coord_to_idx, adj, nodes)
            if path and len(path) > 0:
                next_node = path[0]
                if next_node in neighbor_set:
                    return next_node

    # 4. Fallback: any unvisited neighbor
    for nb in neighbors:
        if tuple(nb) not in visited_nodes:
            return tuple(nb)
    # 5. Last resort
    return tuple(neighbors[0])


def run_episode(env):
    """Run single episode, return (success, explored_rate, travel_distance)."""
    obs = env.reset()
    nodes = obs['nodes']
    robot_pos = obs['robot_pos']
    start_node = closest_node_to(robot_pos, nodes)
    if start_node is None:
        # fallback: any node
        start_node = (nodes[0]['coords'][0], nodes[0]['coords'][1])
    current_node = start_node
    visited_nodes = set()
    travel_distance = 0.0
    last_pos = robot_pos

    for step in range(128):
        coord_to_idx, adj = build_graph(nodes)
        target = smart_policy(obs, current_node, coord_to_idx, adj, nodes, visited_nodes)
        if target is None:
            break
        # track distance before moving
        obs, info = env.step(target)
        # update travel distance
        new_pos = obs['robot_pos']
        travel_distance += euclidean(last_pos, new_pos)
        last_pos = new_pos
        visited_nodes.add(tuple(target))
        current_node = tuple(target)
        nodes = obs['nodes']
        if info.get('done', False):
            break

    metrics = env.get_metrics()
    success = metrics.get('success', False)
    explored_rate = metrics.get('explored_rate', 0.0)
    # use metrics travel_distance to be consistent
    travel_distance = metrics.get('travel_distance', travel_distance)
    return success, explored_rate, travel_distance


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    # Load eval configuration
    config_file = os.path.join(args.data_path, 'eval_config.json')
    with open(config_file) as f:
        config = json.load(f)

    maps = config.get('maps', [])  # list of relative map paths
    if not maps:
        # fallback: scan maps_eval directory
        maps_eval_dir = os.path.join(args.data_path, 'maps_eval')
        for env_type in ['room', 'tunnel', 'outdoor']:
            type_dir = os.path.join(maps_eval_dir, env_type)
            if os.path.isdir(type_dir):
                for fname in sorted(os.listdir(type_dir)):
                    if fname.endswith('.png'):
                        maps.append(os.path.join(env_type, fname))

    results = {
        "per_episode": [],
        "per_type": {},
        "total_episodes": len(maps),
    }
    type_stats = {
        t: {"success_count": 0, "total_distance": 0.0, "total_explored": 0.0, "count": 0}
        for t in ["room", "tunnel", "outdoor"]
    }

    for map_rel in maps:
        # Determine environment type from path
        if 'room' in map_rel:
            env_type = 'room'
        elif 'tunnel' in map_rel:
            env_type = 'tunnel'
        elif 'outdoor' in map_rel:
            env_type = 'outdoor'
        else:
            env_type = 'unknown'
        map_path = os.path.join(args.data_path, 'maps_eval', map_rel)
        if not os.path.exists(map_path):
            map_path = os.path.join(args.data_path, map_rel)  # fallback
        env = ExplorationEnv(map_path=map_path)
        success, explored_rate, travel_distance = run_episode(env)
        # env has no close()
        results["per_episode"].append({
            "map_path": map_rel,
            "env_type": env_type,
            "success": int(success),
            "travel_distance": travel_distance,
            "explored_rate": explored_rate,
        })
        ts = type_stats.get(env_type)
        if ts is not None:
            ts["count"] += 1
            ts["total_explored"] += explored_rate
            ts["total_distance"] += travel_distance
            if success:
                ts["success_count"] += 1

    # Aggregate overall metrics
    total_success = sum(ep["success"] for ep in results["per_episode"])
    total_explored = sum(ep["explored_rate"] for ep in results["per_episode"])
    successful_distances = [ep["travel_distance"] for ep in results["per_episode"] if ep["success"]]
    results["success_rate"] = total_success / len(maps) if maps else 0.0
    results["explored_rate"] = total_explored / len(maps) if maps else 0.0
    results["travel_distance"] = (sum(successful_distances) / len(successful_distances)) if successful_distances else 0.0

    for env_type, ts in type_stats.items():
        if ts["count"] > 0:
            results["per_type"][env_type] = {
                "explored_rate": ts["total_explored"] / ts["count"],
                "travel_distance": ts["total_distance"] / ts["count"],
                "success_rate": ts["success_count"] / ts["count"],
            }
        else:
            results["per_type"][env_type] = {
                "explored_rate": 0.0,
                "travel_distance": 0.0,
                "success_rate": 0.0,
            }

    with open(args.output, 'w') as f:
        json.dump(results, f, indent=2)
    print(f"Evaluation complete: {len(maps)} maps, success_rate={results['success_rate']:.4f}", flush=True)


if __name__ == '__main__':
    main()
